terraform {

  backend "s3" {
    bucket = "terraform-state-meltwater-wrapidity-prod"
    key    = "k8s/service/atlas_backend.tfstate"
    region = "eu-west-1"
    encrypt = true
  }
  required_version = "~> 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 6.0"
    }
  }
}

provider "kubernetes" {
  host                   = "https://api.ew1k8s2.prod.foundation.meltwater.io"
  cluster_ca_certificate = data.aws_kms_secrets.secrets.plaintext["kubernetes_cluster_ca_certificate"]
  token                  = data.aws_kms_secrets.secrets.plaintext["kubernetes_wrapidity_drone_token"]
}
provider "aws" {
  region = var.aws_region
  default_tags {
    tags = merge({
      Name       = "Atlas Backend",
      Service    = var.atlas_backend_name
    },
      var.common_tags)
  }
}

