data "aws_kms_secrets" "secrets" {
  #  aws kms encrypt --key-id $KEY_ID --plaintext fileb://~/.kube/certs/kubernetes/k8s-ca.crt  --output text --query CiphertextBlob
  secret {
    name    = "kubernetes_cluster_ca_certificate"
    payload = ""
  }

  #aws kms encrypt --key-id $KEY_ID --plaintext fileb://<(echo -n $( kubectl describe secret/wrapidity-prod-drone-deploy-token-rf6xg -n wrapidity-prod | grep '^token:' | awk '{print $2}' | tr -d "\n" )) --output text --query CiphertextBlob
  secret {
    name    = "kubernetes_wrapidity_drone_token"
    payload = ""
  }

  secret {
    name    = "urlbank_db_password"
    payload = var.url_collector_encrypted_password
  }
}

locals {
  kubernetes_namespace = "${var.team}-${var.env_name}"
}
